module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

reg [15:0] partial_product [7:0];
reg [7:0] shift_reg [7:0];
reg [3:0] i, j;

always @(*) begin
    for (i = 0; i < 8; i = i + 1) begin
        partial_product[i] = A & {8{B[i]}};
        shift_reg[i] = B[i] ? (A << i) : 8'b0;
    end
    product = 16'b0;
    for (j = 0; j < 8; j = j + 1) begin
        product = product + partial_product[j];
    end
end

endmodule
